const rawApiBase=window.API_BASE_URL||window.PPS_API_BASE||("localhost"===window.location?.hostname||"127.0.0.1"===window.location?.hostname?"http://127.0.0.1:5000":window.location?.origin||"");export const API_BASE=String(rawApiBase||"").replace(/\/+$/,"");export async function fetchProducts(){try{const t=await fetch(`${API_BASE}/api/products`,{cache:"no-store"});if(!t.ok)throw new Error("Failed to fetch products");return await t.json()}catch(t){return console.error("API Error:",t),[]}}export async function fetchProductBySlug(t){return(await fetchProducts()).find(e=>e.slug===t)}export async function fetchReviews(t){try{const e=await fetch(`${API_BASE}/api/reviews?productId=${t}`,{cache:"no-store"});return e.ok?await e.json():{reviews:[],average:0,count:0}}catch(t){return{reviews:[],average:0,count:0}}}export const formatMoney=(t,e="CAD")=>new Intl.NumberFormat("en-CA",{style:"currency",currency:e}).format(t/100);export async function loginUser(t,e){return(await fetch(`${API_BASE}/api/auth/login`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({email:t,password:e})})).json()}export async function sendVerificationCode(t,e){return(await fetch(`${API_BASE}/api/auth/send-code`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({email:t,name:e})})).json()}export async function verifyCode(t,e){return(await fetch(`${API_BASE}/api/auth/check-code`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({email:t,code:e})})).json()}export async function registerUser(t){return(await fetch(`${API_BASE}/api/auth/register`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(t)})).json()}export async function fetchUserOrders(t){const e=await fetch(`${API_BASE}/api/account/orders`,{headers:{Authorization:`Bearer ${t}`}});if(401===e.status)throw new Error("Unauthorized");return e.json()}export async function submitContact(t){return(await fetch(`${API_BASE}/api/contact`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(t)})).json()}export async function submitFeedback(t){return(await fetch(`${API_BASE}/api/feedback`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(t)})).json()}export async function fetchAdminOrders(){return(await fetch(`${API_BASE}/api/admin/orders`,{cache:"no-store"})).json()}export async function fulfillOrder(t){const e=await fetch(`${API_BASE}/api/admin/orders/${t}/fulfill`,{method:"POST"});if(!e.ok)throw new Error("Failed to fulfill");return e.json()}export async function fetchAdminMessages(){return(await fetch(`${API_BASE}/api/admin/messages`,{cache:"no-store"})).json()}
